import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an object with mutable map property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someMap: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with mutable list property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someList: MutableList<String> = mutableListOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with mutable set property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someSet: MutableSet<String> = mutableSetOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with mutable collection property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someCollection: MutableCollection<String> = mutableListOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with ArrayList property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someList: ArrayList<String> = ArrayList()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with HashMap property in lower camel case then do not emit`() {
        val code =
            """
            object DumObjectName {
                val someMap: HashMap<String, String> = HashMap()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object with mutable map property in screaming snake case then emit error`() {
        val code =
            """
            object DumObjectName {
                val SOME_MAP: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should start with a lowercase letter and use camel case")
    }

    @Test
    fun `Given an object with immutable map property in lower camel case then emit error`() {
        val code =
            """
            object DumObjectName {
                val someMap: Map<String, String> = mapOf()
            }
            """.trimIndent()
        @Suppress("ktlint:standard:argument-list-wrapping", "ktlint:standard:max-line-length")
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should use the screaming snake case notation when the value can not be changed")
    }

    @Test
    fun `Given a top level mutable map property in lower camel case then do not emit`() {
        val code =
            """
            val someMap: MutableMap<String, String> = mutableMapOf()
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level mutable list property in lower camel case then do not emit`() {
        val code =
            """
            val someList: MutableList<String> = mutableListOf()
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level immutable list property in lower camel case then emit error`() {
        val code =
            """
            val someList: List<String> = listOf()
            """.trimIndent()
        @Suppress("ktlint:standard:argument-list-wrapping", "ktlint:standard:max-line-length")
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(1, 5, "Property name should use the screaming snake case notation when the value can not be changed")
    }

    @Test
    fun `Given a companion object with mutable map property in lower camel case then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someMap: MutableMap<String, String> = mutableMapOf()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a companion object with immutable map property in lower camel case then emit error`() {
        val code =
            """
            class Foo {
                companion object {
                    val someMap: Map<String, String> = mapOf()
                }
            }
            """.trimIndent()
        @Suppress("ktlint:standard:argument-list-wrapping", "ktlint:standard:max-line-length")
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(3, 13, "Property name should use the screaming snake case notation when the value can not be changed")
    }
}
"}

